export const category = "database_extras";
export const questions = [{"category":"database_extras","difficulty":"medium","type":"short_answer","title":"数据库透明加密 TDE","content":"请解释数据库透明加密（TDE）的原理及其在数据安全中的作用。","answer":"答案：TDE 在数据库存储层透明地加密数据文件，防止物理介质泄露导致的数据泄露\n\n解析：TDE 的核心原理是在数据写入磁盘时加密、读取时解密，对上层应用完全透明。MySQL 的 TDE 实现（MySQL Enterprise TDE / Percona Server）：使用表空间加密（tablespace encryption），每个表空间有自己的加密密钥，主密钥保存在 KMIP 或文件系统中。InnoDB 在将缓冲池中的 dirty page 写入磁盘前用 AES-256 加密，读入时解密。redo log 和 undo log 也加密。性能影响：加密/解密在 CPU 上进行，选用 AES-NI 指令集的 CPU 可大幅降低开销（通常 3-5% 性能影响）。\n\n扩展延伸：密钥层次架构：主密钥（Master Key） -> 表空间密钥（Tablespace Key）。主密钥由外部 KMS（密钥管理服务）管理，表空间密钥由主密钥加密后存储在表空间头部。层次化设计的优势在于：更换主密钥时只需重新加密表空间密钥（Key Rotation），无需重新加密整个数据库。合规要求：TDE 是 PCI-DSS、GDPR、HIPAA 等合规审查中的常见要求。TDE 的局限：不能防护传输过程中的攻击（需配合 TLS）、不能防护 SQL 注入和数据访问权限滥用（需配合访问控制和审计）。在云环境中建议使用云厂商的 KMS（AWS KMS / Azure Key Vault / 阿里云 KMS）管理主密钥。","hints":["TDE 为什么使用两层密钥架构","TDE 能防御哪些攻击场景"],"tags":["数据库","加密","安全"],"id":1164},{"category":"database_extras","difficulty":"hard","type":"short_answer","title":"PostgreSQL 并行查询","content":"解释 PostgreSQL 并行查询的执行模型。什么是并行顺序扫描、并行哈希连接、并行聚合？哪些 GUC 参数控制并行行为？哪些查询类型不支持并行？","answer":"答案：PostgreSQL 采用 Leader-Worker 模型实现并行查询。\\n\\n并行操作类型：\\n1. 并行顺序扫描（Parallel Seq Scan）：将表的数据块分配给多个 Worker 并行读取，Leader 负责汇总结果。\\n2. 并行哈希连接（Parallel Hash Join）：多个 Worker 协作构建哈希表，然后并行探测。\\n3. 并行聚合（Partial Aggregate）：每个 Worker 做部分聚合，Leader 做最终聚合。\\n\\n关键 GUC 参数：\\n- max_parallel_workers：整个系统的最大并行 Worker 数。\\n- max_parallel_workers_per_gather：单个 Gather 节点能启动的最大 Worker 数。\\n- parallel_tuple_cost / parallel_setup_cost：优化器评估并行执行成本的系数。\\n- min_parallel_table_scan_size：触发并行扫描的最小表大小。\\n\\n不支持并行的场景：\\n- 使用游标（CURSOR）的查询。\\n- 带 PARALLEL UNSAFE 标记的函数。\\n- 某些窗口函数。\\n- 修改数据的 DML（默认限制，PG 11 之后支持部分并行）。\\n- 加锁操作（SELECT FOR UPDATE / FOR SHARE）。\\n\\n并行安全性分为三个级别：PARALLEL SAFE（可以并行）、PARALLEL RESTRICTED（只能在 Leader 上并行）、PARALLEL UNSAFE（不能并行）。","hints":["控制并行度的三个主要 GUC 参数是什么","为什么某些窗口函数和游标查询不支持并行"],"tags":["PostgreSQL","并行查询","性能优化"],"id":1166},{"category":"database_extras","difficulty":"medium","type":"short_answer","title":"冷热数据分离","content":"描述数据库中冷热数据分离的几种常见实现策略。每种策略的优缺点是什么？如何设计分区键和迁移策略？","answer":"答案：冷热数据分离是将频繁访问的「热数据」和不常访问的「冷数据」分开存储，以降低成本并提高性能。\\n\\n常见策略：\\n1. 时间分区法：按时间范围分区（如按月分区），热分区放在快速存储（NVMe SSD），冷分区可移到廉价存储甚至归档。优点是实现简单、查询分区裁剪方便；缺点是热数据也可能包含大量不活跃数据。\\n2. 显式标记法：表中增加 `is_hot` 或 `status` 字段，通过定期 Job 将冷数据迁移到归档表或归档库（如 MySQL 到 ClickHouse）。优点是灵活控制；缺点是需要应用层感知多表路由。\\n3. 存储分层法：利用存储引擎的分层能力（如 LSMTree 的 Tiered Compaction、MySQL 的分区表放在不同磁盘路径）。优势是对应用透明。\\n4. 缓存加速法：热数据在 Redis/Memcached 中缓存，数据库作为完整数据的持久层。简单有效，但需要处理缓存一致性问题。\\n\\n迁移策略考虑：\\n- 迁移窗口：冷数据迁移通常在业务低峰期执行。\\n- 数据一致性：迁移过程中需保证未迁移数据的一致性，可通过双写或校验机制。\\n- 降级策略：如果迁移失败，应有回滚机制。","hints":["最简单也最常见的分离标准是什么？它有什么局限性","存储分层法对应用透明意味着什么"],"tags":["数据库设计","冷热分离","性能优化","架构"],"id":1167},{"category":"database_extras","difficulty":"hard","type":"short_answer","content":"MySQL 8.0 窗口函数的执行模型是什么？优化器如何选择执行策略？如何设计索引和查询以优化窗口函数性能？ROWS、RANGE、GROUPS 三种帧模式有什么区别？","title":"MySQL 8.0 窗口函数优化","answer":"答案：MySQL 8.0 窗口函数执行分为三个步骤：\\n1. Partition：按 PARTITION BY 分组。\\n2. Order：在每个分组内按 ORDER BY 排序。\\n3. Frame：在定义好的窗口帧上计算函数值。\\n\\n执行策略：\\n- 默认策略：使用临时表 + filesort（如果排序量超过 sort_buffer_size）。\\n- 优化器可在某些场景选择 BNL（Batched Key Access）策略。\\n\\n三种帧模式：\\n- ROWS：物理行偏移（如 ROWS BETWEEN 1 PRECEDING AND 1 FOLLOWING）。最精确、最高效。\\n- RANGE：逻辑值范围（同一 ORDER BY 值视为一组）。性能较 ROWS 差。\\n- GROUPS：分组范围（ORDER BY 值相同的行视为一组）。MySQL 8.0.14 引入。\\n\\n优化建议：\\n1. 创建匹配 PARTITION BY + ORDER BY 的联合索引——大幅减少排序开销。\\n2. 优先使用 ROWS 而非 RANGE/GROUPS。\\n3. 避免对大结果集无 PARTITION BY 的窗口函数（全局排序单线程）。\\n4. 用 ROW_NUMBER() 替代 GROUP BY + 子查询实现分组 Top-N（性能更好）。\\n5. 善用窗口函数替代自连接，减少 IO。\\n6. 控制 `windowing_use_high_precision` 参数（高精度模式有额外开销）。\\n7. 子查询中使用窗口函数时，外层要加适当过滤以减少内层处理行数。","hints":["什么索引设计能同时加速 PARTITION BY 和 ORDER BY 两个步骤","ROWS 和 RANGE 帧模式在性能上的关键差异是什么"],"tags":["MySQL","窗口函数","查询优化","性能"],"id":1168},{"category":"database_extras","difficulty":"easy","type":"true_false","title":"InnoDB 独立表空间与共享表空间","content":"InnoDB 每个表一个独立表空间文件（.ibd）一定比共享表空间（ibdata1）更好。（判断对错）","options":["A) 正确","B) 错误"],"answer":"错误\n\n解析：独立表空间（每个表一个 .ibd 文件）和共享表空间（系统表空间 ibdata1）各有优劣。独立表空间支持收缩（ALTER TABLE DISCARD/IMPORT TABLESPACE）、表级别备份、DROP TABLE 直接删除文件。共享表空间无法收缩（DELETE 大量数据后空间不释放）、所有表共享 ibdata1 文件。MySQL 5.6+ 默认使用独立表空间。独立表空间的缺点是每个表都要打开文件描述符，大量小表时浪费 inode。","hints":["DROP TABLE 操作释放的是独立表空间（.ibd）还是系统表空间（ibdata1）","ibdata1 中存储了哪些不会随 DROP TABLE 释放的数据"],"tags":["MySQL","InnoDB","表空间","存储管理"],"id":1169},{"category":"database_extras","difficulty":"easy","type":"choice","title":"MySQL 8.0 ALGORITHM=INSTANT 即时 DDL","content":"关于 MySQL 8.0 的 ALGORITHM=INSTANT DDL，以下说法正确的是？","answer":"C) ALGORITHM=INSTANT 只修改数据字典而不重建表，部分 DDL 操作（如加列）可以使用该算法\n\n解析：MySQL 8.0.12+ 引入 ALGORITHM=INSTANT，支持的 DDL 操作包括在表末尾加列（非 array 类型）、加/删索引（但索引操作实质用 INPLACE）、修改列的默认值等。INSTANT 只修改数据字典（metadata），不重建表，因此不阻塞 DML。OLTP 场景下 CTAS 或 LOCK=DEFAULT 可能触发 INSTANT 或回退到 INPLACE。\n\n扩展延伸：INSTANT 加列不会回填历史数据，新列在老记录的 Record Header 中以「隐含默认值」标记。8.0.29+ 支持 INSTANT DROP COLUMN，但 8.0.29 以下版本只能加不能删。同一张表使用 INSTANT 加列次数受 row_format 和列数限制（通常约 64 次）。","options":["A) ALGORITHM=INSTANT 和 ALGORITHM=INPLACE 完全相同","B) ALGORITHM=INSTANT 会在 DDL 执行期间阻塞所有 DML","C) ALGORITHM=INSTANT 只修改数据字典而不重建表，部分 DDL 操作（如加列）可以使用该算法","D) ALGORITHM=INSTANT 重建整个表但比 COPY 快"],"hints":["INSTANT 加列后老数据行如何表示新列","INSTANT 操作有次数限制吗"],"tags":["MySQL","DDL","在线变更","性能优化"],"id":1171},{"category":"database_extras","difficulty":"medium","type":"true_false","title":"MySQL 8.0 CHECK 约束","content":"MySQL 8.0.16 开始支持 CHECK 约束，但 CHECK 约束只对 INSERT 操作生效，对 UPDATE 操作无效。","answer":"错误\n\n解析：MySQL 8.0.16+ 的 CHECK 约束对 INSERT 和 UPDATE 操作都生效。当插入新行或更新现有行时，如果 CHECK 约束条件不满足则操作被拒绝。MySQL 对 CHECK 约束的实现符合 SQL 标准，支持列级约束和表级约束。在 8.0.16 之前 MySQL 虽然解析 CHECK 子句但不会实际验证数据。\n\n扩展延伸：CHECK 约束可以包含复杂表达式（如 JSON_VALID、多个列的比较），但不可包含子查询和存储函数。启用/禁用约束需要重建表（ALTER TABLE ... ALTER CHECK ... ENFORCED/NOT ENFORCED）。推荐使用 CHECK 约束而非触发器来实现简单的列值校验，因为 CHECK 约束优化器感知且执行效率更高。","options":["正确","错误"],"hints":["CHECK 约束对哪种 DML 操作生效","MySQL 8.0.16 之前 CHECK 子句是什么行为"],"tags":["MySQL","CHECK约束","数据校验","DDL"],"id":1172},{"category":"database_extras","difficulty":"medium","type":"short_answer","title":"Redis vs Memcached 对比","content":"请对比 Redis 和 Memcached 的核心差异和适用场景。","answer":"答案：Redis 和 Memcached 都是内存缓存系统，但设计目标和能力差异很大。\n\n核心差异：\n\n| 维度 | Redis | Memcached |\n|------|-------|-----------|\n| 数据结构 | 丰富（String, Hash, List, Set, Sorted Set, HyperLogLog, GEO, Stream） | 仅 Key-Value（值只能是字符串） |\n| 持久化 | RDB（快照）, AOF（日志） | 不支持 |\n| 主从复制 | 支持 | 不支持 |\n| 集群 | Redis Cluster（去中心化哈希槽） | 客户端分片（一致性哈希） |\n| 内存淘汰 | 8 种策略（LRU, LFU, TTL, Random 等） | LRU 为主 |\n| 线程模型 | 6.x 前单线程，6.x 后多线程 I/O | 多线程（多线程处理 I/O + 多线程处理命令） |\n| 事务 | 支持（MULTI/EXEC，WATCH 乐观锁） | 不支持 |\n| Lua 脚本 | 支持 | 不支持 |\n| 发布订阅 | 支持 | 不支持 |\n| 内存效率 | 较高（数据结构有额外开销） | 高（纯 KV，开销最小） |\n\nRedis 优势：\n- 丰富的数据结构支持复杂业务逻辑\n- 持久化保证数据不丢失\n- 主从复制和集群实现高可用\n- 适合从简单缓存到复杂业务场景\n\nMemcached 优势：\n- 多线程处理，在多核机器上 CPU 利用更充分\n- 纯 KV 设计，内存效率最高\n- 实现极简单，定位非常纯粹\n- 在大值缓存场景下性能更好\n\n选择建议：\n- 需要缓存以外的能力（数据结构、持久化、Pub/Sub）→ Redis\n- 超大并发、超大缓存（纯 KV 场景）→ Memcached\n- 默认选择 → Redis（生态更丰富、社区更活跃）\n\n扩展延伸：Redis 的定位已经从缓存进化为实时数据平台（Real-Time Data Platform）。Redis Stack（RedisJSON, RedisSearch, RedisTimeSeries, RedisGraph）进一步扩展了能力边界。","hints":["Redis：丰富数据结构、持久化、主从复制、集群、Lua 脚本（通用缓存+数据平台）","Memcached：纯 KV、多线程、高内存效率（简单纯粹的大缓存）","新系统默认选 Redis，纯 KV 超大缓存场景才考虑 Memcached"],"tags":["数据库","Redis","Memcached","缓存"],"id":3572}];
